import XCTest

@testable import Schrift

/// Byte-exact regression tests for the Yjs update encoder. The expected bytes
/// are golden fixtures generated by the real `yjs` library (`Y.encodeStateAsUpdate`
/// over `blocksToYDoc(blocks, "document-store")`) with clientID 0xDEADBEEF, so a
/// pass means the Swift encoder is wire-compatible with yjs itself.
final class YjsEncoderTests: XCTestCase {
    private let clientID: UInt32 = 0xDEAD_BEEF

    private func hex(_ data: Data) -> String { data.map { String(format: "%02x", $0) }.joined() }
    private func U(_ n: Int) -> String { String(format: "%04x", n) + "0000-0000-4000-8000-000000000000" }
    private var P: [(key: String, value: YAnyValue)] {
        [
            ("backgroundColor", .string("default")), ("textColor", .string("default")),
            ("textAlignment", .string("left")),
        ]
    }
    private func para(_ runs: [InlineRun], _ id: Int) -> BlockNoteBlock {
        BlockNoteBlock(node: "paragraph", props: P, runs: runs, id: U(id))
    }
    private func assertGolden(
        _ blocks: [BlockNoteBlock], _ expected: String, _ message: String = "", file: StaticString = #filePath,
        line: UInt = #line
    ) {
        XCTAssertEqual(hex(BlockNoteYjs.encode(blocks, clientID: clientID)), expected, message, file: file, line: line)
    }

    func testEmptyParagraph() {
        assertGolden(
            [para([], 1)],
            ""
        )
    }

    func testParagraph() {
        assertGolden(
            [para([InlineRun("Just a paragraph.")], 1)],
            ""
        )
    }

    func testHeadingLevel2() {
        let block = BlockNoteBlock(
            node: "heading", props: P + [("level", .int(2)), ("isToggleable", .bool(false))],
            runs: [InlineRun("Heading two")], id: U(1))
        assertGolden(
            [block],
            ""
        )
    }

    func testBoldRun() {
        assertGolden(
            [para([InlineRun("Hello "), InlineRun("world", marks: [("bold", "{}")])], 1)],
            ""
        )
    }

    func testMultipleInlineMarks() {
        let runs = [
            InlineRun("Some "), InlineRun("italic", marks: [("italic", "{}")]), InlineRun(" and "),
            InlineRun("bold", marks: [("bold", "{}")]), InlineRun(" and "), InlineRun("code", marks: [("code", "{}")]),
            InlineRun(" here."),
        ]
        assertGolden(
            [para(runs, 1)],
            ""
        )
    }

    func testBulletList() {
        let blocks = [
            BlockNoteBlock(node: "bulletListItem", props: P, runs: [InlineRun("one")], id: U(1)),
            BlockNoteBlock(node: "bulletListItem", props: P, runs: [InlineRun("two")], id: U(2)),
        ]
        assertGolden(
            blocks,
            ""
        )
    }

    func testNumberedListHasStartProp() {
        let blocks = [
            BlockNoteBlock(
                node: "numberedListItem", props: P + [("start", .null)], runs: [InlineRun("first")], id: U(1)),
            BlockNoteBlock(
                node: "numberedListItem", props: P + [("start", .null)], runs: [InlineRun("second")], id: U(2)),
        ]
        assertGolden(
            blocks,
            ""
        )
    }

    func testCheckListHasCheckedProp() {
        let blocks = [
            BlockNoteBlock(
                node: "checkListItem", props: P + [("checked", .bool(false))], runs: [InlineRun("todo")], id: U(1)),
            BlockNoteBlock(
                node: "checkListItem", props: P + [("checked", .bool(true))], runs: [InlineRun("done")], id: U(2)),
        ]
        assertGolden(
            blocks,
            ""
        )
    }

    func testQuoteHasNoAlignment() {
        let block = BlockNoteBlock(
            node: "quote", props: [("backgroundColor", .string("default")), ("textColor", .string("default"))],
            runs: [InlineRun("quoted")], id: U(1))
        assertGolden(
            [block],
            ""
        )
    }

    func testCodeBlockHasLanguage() {
        let block = BlockNoteBlock(
            node: "codeBlock", props: [("language", .string("swift"))], runs: [InlineRun("let x = 1")], id: U(1))
        assertGolden(
            [block],
            ""
        )
    }

    func testDividerHasNoTextChild() {
        let blocks = [
            para([InlineRun("above")], 1),
            BlockNoteBlock(node: "divider", props: [], runs: [], id: U(2)),
            para([InlineRun("below")], 3),
        ]
        assertGolden(
            blocks,
            ""
        )
    }

    func testLinkMark() {
        let runs = [
            InlineRun("See "), InlineRun("docs", marks: [("link", "{\"href\":\"https://example.com\"}")]),
            InlineRun(" now"),
        ]
        assertGolden(
            [para(runs, 1)],
            ""
        )
    }

    func testStrikeLeadingMark() {
        let runs = [InlineRun("gone", marks: [("strike", "{}")]), InlineRun(" text")]
        assertGolden(
            [para(runs, 1)],
            ""
        )
    }

    func testUnicodeUsesUtf16LengthAndUtf8Bytes() {
        assertGolden(
            [para([InlineRun("café 😀 end")], 1)],
            ""
        )
    }

    /// An image is a leaf (no `xmlText` child) that still carries props. Golden
    /// bytes captured like every fixture here: real yjs `Y.encodeStateAsUpdate`
    /// over `blocksToYDoc(blocks, "document-store")`, @blocknote/core 0.51.4 (the
    /// version the docs frontend pins), clientID 0xDEADBEEF. Prop order matches
    /// the 0.51.4 image propSchema. `previewWidth` is emitted as `undefined`
    /// (0x7f), NOT omitted — confirmed empirically against the real library; the
    /// image block has no `textColor`.
    func testImageBlockIsLeafWithProps() {
        let block = BlockNoteBlock(
            node: "image",
            props: [
                ("textAlignment", .string("left")),
                ("backgroundColor", .string("default")),
                ("name", .string("photo.jpg")),
                (
                    "url",
                    .string(
                        "https://docs.example.test/media/11111111-1111-4111-8111-111111111111/attachments/22222222-2222-4222-8222-222222222222.jpg"
                    )
                ),
                ("caption", .string("")),
                ("showPreview", .bool(true)),
                ("previewWidth", .undefined),
            ],
            runs: [], id: U(1))
        assertGolden(
            [block],
            ""
        )
    }
}
